import{_ as p,o as i,c as o,ag as r}from"./chunks/framework.DtEl18Xn.js";const S=JSON.parse('{"title":"HarmonyOS","description":"","frontmatter":{"title":"HarmonyOS ","category":"产品更新说明","lastUpdated":"2026-03-14T15:00:43.434Z"},"headers":[],"relativePath":"产品更新说明/harmonyos-.md","filePath":"产品更新说明/harmonyos-.md"}'),n={name:"产品更新说明/harmonyos-.md"};function a(t,l,s,e,u,m){return i(),o("div",null,[...l[0]||(l[0]=[r('<h1 id="harmonyos" tabindex="-1">HarmonyOS <a class="header-anchor" href="#harmonyos" aria-label="Permalink to &quot;HarmonyOS&quot;">​</a></h1><p>鸿蒙 HarmonyOS 版本已上线！在应用市场搜索「Get笔记」即可下载。</p><ul><li><p><strong>HarmonyOS v2.6.2 🎉</strong></p></li><li><p>GetSeed录音卡新增「AI柳比歇夫」日记功能，每天帮你把当日的录音卡笔记整理成一篇专属日记。</p></li><li><p>笔记发芽功能，支持对单条录音卡笔记进行“发芽”。</p></li><li><p>**HarmonyOS v2.6.1 **</p></li><li><p>支持「声纹识别」：让AI认识你的声音，自动标记你说的话，回溯记录更便捷；</p></li><li><p>新增「语音口令」：录音时只需说出“标记一下”等口令词，AI 即可在笔记中标记重点，解放双手；</p></li><li><p>优化「纠错替换」：支持对录音笔记一键替换纠错，大幅提升修改速度，会议、内录、课堂、录音卡笔记都可用。</p></li><li><p>**HarmonyOS v2.6.0 ** 1.「文字记录」全面升级</p></li><li><p>批量纠错：长按快速查找替换，错别字一键修正</p></li><li><p>AI优化版：智能优化专有名词和口水词，内容更易读</p></li><li><p>说话人筛选：单独查看某人的发言，快速定位关键内容</p></li></ul><p>2.播放器体验优化</p><ul><li><p>倍速播放：0.5x-3x自由调速，高效回听录音内容</p></li><li><p>跳过空白：自动过滤沉默片段，节省宝贵时间</p></li></ul><p>3.笔记管理更便捷</p><ul><li><p>多维筛选：按类型、来源平台筛选过滤，找笔记更高效</p></li><li><p>标题快改：点击即可修改笔记标题，更快更方便</p></li><li><p><strong>HarmonyOS v2.4.9</strong></p></li><li><p>录音卡同步更稳定，不再担心卡顿丢失</p></li><li><p>修复了特殊机型获取不到录音卡蓝牙状态的问题</p></li><li><p>笔记复制粘贴体验优化</p></li><li><p><strong>HarmonyOS v2.4.8</strong></p></li><li><p>录音卡支持快传功能，录音传输更快捷</p></li><li><p><strong>HarmonyOS v2.4.3</strong></p></li><li><p>提升蓝牙连接稳定性，设备连接更可靠</p></li><li><p>固件升级过程更顺滑，传输录音不受影响</p></li><li><p>修复知识库文件上传不成功的问题</p></li><li><p><strong>HarmonyOS v2.4.2</strong> 支持 Get 笔记录音卡片相关功能：</p></li><li><p>搭配录音卡使用，通话、会议也能录</p></li><li><p>录音过程中，一键 Mark 重点，关键内容即时标记</p></li><li><p>支持记录闪念，灵感随时留存</p></li><li><p>录音完成后，笔记在 App 内持续整理、生长</p></li><li><p>轻薄便携，贴在手机背后，随时待命</p></li><li><p>**HarmonyOS v2.3.4 **</p></li><li><p>上线手机内录功能！可边播放边记录</p></li><li><p>开启双11年度特惠，会员买1年送1年！</p></li><li><p>购买会员支持微信支付</p></li><li><p>追加笔记数量展示更直观</p></li><li><p>修复追加笔记重复显示问题</p></li><li><p>**HarmonyOS v2.3.0 ** 本更新可让你：</p></li><li><p>邀请好友注册并使用Get笔记，得会员奖励</p></li><li><p>自主更换绑定的手机号，账号管理更灵活</p></li><li><p>在链接笔记中查看原文逐字稿更便捷</p></li><li><p>语音词库识别更准确，听懂你的专业词汇</p></li><li><p>**HarmonyOS v2.2.1 ** 本更新可让你:</p></li><li><p>享受更准确的粤语识别，转写更流畅</p></li><li><p>「智能拍书」更灵活，可从相册选取照片识别</p></li><li><p>在录音笔记「文字记录」页，发言人旁新增 播放/暂停按钮，你可以单独播放对应片段，更加精准定位语音内容</p></li><li><p><strong>HarmonyOS v2.2.0</strong> 本更新可让你：</p></li></ul><p>【智能拍书，好记好找】</p><ul><li>对准书页拍一下，自动提取归类到书籍</li></ul><p>【书籍视图，一目了然】</p><ul><li>笔记按书籍自动归类，告别翻找困扰</li></ul><p>【拥有最懂你的AI读书伙伴】</p><ul><li><p>书籍+笔记双重加持，AI陪你吃透每本书</p></li><li><p><strong>HarmonyOS v2.1.6</strong> 本更新可让你：</p></li><li><p>使用全新侧边栏，快速访问Get日报和知识库</p></li><li><p>按日历查看笔记，热力图直观展示记录频率</p></li><li><p>自由增删改标签，笔记整理更灵活</p></li><li><p>录音过程中随时修改标题，命名更便捷</p></li><li><p>**HarmonyOS v2.1.0 ** 本更新可让你:</p></li></ul><p>【链接分享笔记】</p><ul><li><p>笔记链接包含图文与音频，分享更完整</p></li><li><p>一键转发微信/朋友圈，好友能看能听</p></li><li><p>可选是否分享音频部分，便捷与隐私兼得</p></li></ul><p>【多图转笔记】</p><ul><li><p>拍书页/拍会议/拍PPT，随手拍下重点</p></li><li><p>一次上传10张图片，AI快速生成笔记</p></li></ul><p>【会议记录更懂你】</p><ul><li><p>会议录音中，可随时输入想法或拍照补充</p></li><li><p>AI总结时，优先关注你记录的关键信息</p></li><li><p>个性化设置发言人名称，会议回顾更清晰</p></li></ul><p>【知识库权限可控】</p><ul><li>自主设置知识库内容可读权限，保护隐私</li></ul><p>【一键清理缓存】</p><ul><li><p>设置内轻松清理，释放设备空间</p></li><li><p>**HarmonyOS v2.0.2 ** 本更新可让你：</p></li><li><p>自由修改知识库中文件名称。</p></li><li><p>跨知识库移动文件、笔记。</p></li><li><p>查看更美观的公式排版。</p></li><li><p>生成图文并茂的AI链接笔记。</p></li><li><p>体验多项界面优化和问题修复。</p></li><li><p><strong>HarmonyOS v2.0.1</strong> 【全新AI助手】</p></li><li><p>AI助手来啦！支持了连续对话；</p></li><li><p>像聊天一样提问，AI助手陪你把知识聊透。</p></li></ul><p>【得到内容接入】</p><ul><li><p>得到海量好课好书，都是你的素材库；</p></li><li><p>提问可选择笔记、知识库、全网及得到内容，AI回答更靠谱。</p></li></ul><p>【Get日报】</p><ul><li><p>笔记和订阅内容有更新，AI为你提炼生成回顾日报；</p></li><li><p>每天几分钟，轻松掌握所有你关心的新内容。</p></li></ul><p>【提问更灵活】</p><ul><li><p>支持上传图片/文件，或直接选择笔记提问；</p></li><li><p>可指定单个/多个知识库提问，或在笔记/知识库中直接开聊；</p></li><li><p>多种方式可自由组合，满足不同场景需求。</p></li><li><p><strong>HarmonyOS v1.2.9</strong> 【导入音视频文件】</p></li><li><p>支持音视频文件上传，AI转写并生成总结笔记，单文件最长3小时；</p></li><li><p>轻松整理课程、会议、访谈和演讲等冗长录音内容。</p></li></ul><p>【图片笔记升级】</p><ul><li><p>智能OCR上线，逐字还原，细节一条不漏；</p></li><li><p>读书摘录、培训PPT、白板记录等场景，拍张照片秒变条理清晰笔记。</p></li></ul><p>【个人语音词库】</p><ul><li><p>AI根据以往笔记智能分析热词，也可自定义专有名词；</p></li><li><p>提升录音识别准确度，让各领域内容记录更准确可靠。</p></li></ul><p>【笔记导出升级】</p><ul><li><p>文本笔记可以导出PDF和DOCX两种格式文件；</p></li><li><p>录音笔记支持MP3文件导出，分享更便捷。</p></li><li><p>**HarmonyOS v1.2.8 ** 【线下会议录音】</p></li><li><p>线下开会，打开录音，Get笔记可智能区分发言人，实时转录。</p></li><li><p>会议结束瞬间，快速提炼会议纪要。</p></li><li><p>单次录音时长，免费用户录制可达 1 小时，会员用户可录制 2 小时。</p></li></ul><p>【知识广场】可以在知识广场搜索发现更多领域宝藏知识库；也可以选择将自己的知识库一键发布到知识广场。</p><p>【个性设置】知识库支持添加自定义封面，让你的知识管理更具个人风格，一眼识别。</p><p>【批量上传】知识库内支持了多选PDF/Word/PPT不同类型文件批量上传，文件整理更高效。</p><ul><li><p><strong>HarmonyOS v1.2.6</strong> 【笔记管理】</p></li><li><p>全部笔记新增分类筛选，文字/录音/链接/图片笔记一目了然；</p></li><li><p>笔记支持移动到知识库指定文件夹，整理更灵活。</p></li></ul><p>【体验升级】</p><ul><li><p>订阅的直播和博主支持同时加入多个知识库；</p></li><li><p>图片笔记支持处理HEIC格式图片；</p></li><li><p>优化录音被打断的使用体验，修复会议录音/手机内录转码过程中点击重试导致的AI总结不完整问题。</p></li></ul>',41)])])}const O=p(n,[["render",a]]);export{S as __pageData,O as default};
